import React from 'react';

function Programs() {
  const programs = [
    { title: 'Technology & Engineering', desc: 'B.Tech, M.Tech, BCA, MCA', color: 'bg-blue-50 text-blue-700 border-blue-100' },
    { title: 'Management Studies', desc: 'BBA, MBA, Integrated Programs', color: 'bg-amber-50 text-amber-700 border-amber-100' },
    { title: 'Design & Architecture', desc: 'B.Des, B.Arch, Planning', color: 'bg-emerald-50 text-emerald-700 border-emerald-100' },
    { title: 'Sciences & Humanities', desc: 'B.Sc, M.Sc, Liberal Studies', color: 'bg-purple-50 text-purple-700 border-purple-100' },
    { title: 'Pharmacy', desc: 'B.Pharm, Pharm.D, M.Pharm', color: 'bg-rose-50 text-rose-700 border-rose-100' },
    { title: 'Certificate Courses', desc: 'IoT, Clinical Research & more', color: 'bg-slate-50 text-slate-700 border-slate-100' },
  ];

  return (
    <div className="fade-in">
      <header className="mb-12">
        <h1 className="text-4xl font-bold text-gray-900 mb-3">Academic Programs</h1>
        <p className="text-lg text-gray-500">Discover your path to success at Indus</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {programs.map((p, i) => (
          <div key={i} className={`p-8 rounded-3xl border ${p.color} flex flex-col justify-between min-h-[280px] hover:shadow-lg hover:-translate-y-1 transition-all duration-300`}>
            <div>
              <h3 className="text-2xl font-bold mb-3">{p.title}</h3>
              <p className="opacity-80 text-lg mb-8 leading-relaxed">{p.desc}</p>
            </div>
            <button className="w-full py-4 bg-white/60 backdrop-blur-md rounded-2xl font-bold shadow-sm hover:bg-white transition-colors border border-black/5">
              View Curriculum Details
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}

export default Programs;
